def _detect_linguistic_signals(text: str) -> dict:
    """Detect nuanced linguistic markers"""
    markers = {
        'first_person': len(re.findall(r'\b(I|me|my)\b', text, re.IGNORECASE)),
        'emotional_words': len(re.findall(r'\b(feel|understand|empathize)\b', text, re.IGNORECASE))
    }
    return markers

def _assess_emotional_tone(text: str) -> float:
    """Basic emotional tone assessment"""
    positive_words = ['good', 'great', 'excellent', 'happy']
    negative_words = ['bad', 'terrible', 'sad', 'angry']
    
    positive_count = sum(text.lower().count(word) for word in positive_words)
    negative_count = sum(text.lower().count(word) for word in negative_words)
    
    return (positive_count - negative_count) / (positive_count + negative_count + 1)

def _identify_identity_signals(text: str) -> list:
    """Extract potential identity signals"""
